## 2. The C / C++ stub – **`pcapng_stubs.cpp`**

> **Important** – the file must be compiled as C++ (`.cpp` or `.cc`).  
> The only external symbols that OCaml sees are the three `CAMLprim` functions
> declared at the bottom of the file.

```cpp
/* ----------------------------------------------------------------------
   pcapng_stubs.cpp – C++ side of the OCaml binding to libpcapng
   ---------------------------------------------------------------------- */

#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/bigarray.h>
#include <caml/custom.h>
#include <caml/fail.h>

#include <string>
#include <exception>

/* ----------------------------------------------------------------------
   The (fictional) libpcapng C++ API.
   ---------------------------------------------------------------------- */
namespace pcapng {

struct frame {
  uint64_t timestamp;      // nanoseconds since epoch
  uint32_t caplen;         // captured length
  uint32_t len;            // original length
  const uint8_t* data;     // points inside the file‑mapped buffer
};

class File {
public:
  explicit File(const std::string& path);
  ~File();

  // Simple forward iterator over frames
  class iterator {
    // implementation hidden – we only need ++, != and * (frame&)
  public:
    iterator& operator++();
    bool operator!=(const iterator&) const;
    const frame& operator*() const;
  };

  iterator begin() const;
  iterator end()   const;
};

} // namespace pcapng

/* ----------------------------------------------------------------------
   OCaml custom block that holds a pointer to pcapng::File.
   ---------------------------------------------------------------------- */
static void pcapng_finalize(value v) {
  pcapng::File* f = *(pcapng::File**)Data_custom_val(v);
  delete f;
}

/* No comparison, hash or serialization needed – we only store the pointer. */
static struct custom_operations pcapng_ops = {
  "pcapng_file_handle",
  pcapng_finalize,
  custom_compare_default,
  custom_hash_default,
  custom_serialize_default,
  custom_deserialize_default,
  custom_compare_ext_default
};

/* ----------------------------------------------------------------------
   Helper: allocate a custom block that owns a pcapng::File*.
   ---------------------------------------------------------------------- */
static value alloc_file(pcapng::File* f) {
  value v = caml_alloc_custom(&pcapng_ops, sizeof(pcapng::File*), 0, 1);
  *(pcapng::File**)Data_custom_val(v) = f;
  return v;
}

/* ----------------------------------------------------------------------
   open_file : string -> t
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_open_file(value v_path) {
  CAMLparam1(v_path);
  const char* path = String_val(v_path);
  try {
    pcapng::File* f = new pcapng::File(std::string(path));
    CAMLreturn(alloc_file(f));
  } catch (const std::exception& e) {
    caml_raise_with_string(*caml_named_value("Stdlib__Failure"), e.what());
  } catch (...) {
    caml_raise_constant(*caml_named_value("Stdlib__Failure"));
  }
}

/* ----------------------------------------------------------------------
   close : t -> unit
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_close(value v_handle) {
  CAMLparam1(v_handle);
  // The custom finaliser will free the object; we just drop the reference.
  // Setting the pointer to nullptr avoids a double‑free if the user calls
  // close twice (the second call becomes a no‑op).
  pcapng::File** p = (pcapng::File**)Data_custom_val(v_handle);
  if (*p != nullptr) {
    delete *p;
    *p = nullptr;
  }
  CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   iter_frames : t -> (frame -> unit) -> unit
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_iter_frames(value v_handle,
                                                value v_cb) {
  CAMLparam2(v_handle, v_cb);
  CAMLlocal5(v_frame, v_ts, v_caplen, v_len, v_data);

  pcapng::File* file = *(pcapng::File**)Data_custom_val(v_handle);
  if (!file) caml_failwith("pcapng: file already closed");

  for (auto it = file->begin(); it != file->end(); ++it) {
    const pcapng::frame& fr = *it;

    /* ------------------------------------------------------------
       Build the OCaml representation of the frame.
       ------------------------------------------------------------ */
    v_ts     = caml_copy_int64((int64_t)fr.timestamp);
    v_caplen = Val_int(fr.caplen);          // fits in a tagged int (<= 2^30)
    v_len    = Val_int(fr.len);

    /* The payload is exposed as a bigarray that points directly at the
       memory owned by libpcapng.  The BIGARRAY flag CAML_BA_EXTERNAL tells
       the GC that it must not try to free the memory. */
    v_data = caml_ba_alloc(CAML_BA_UINT8 | CAML_BA_EXTERNAL,
                          1,                 // 1‑dimensional
                          (char*)fr.data,
                          fr.caplen);

    v_frame = caml_alloc_tuple(4);
    Store_field(v_frame, 0, v_ts);
    Store_field(v_frame, 1, v_caplen);
    Store_field(v_frame, 2, v_len);
    Store_field(v_frame, 3, v_data);

    /* ------------------------------------------------------------
       Invoke the OCaml callback.
       ------------------------------------------------------------ */
    value res = caml_callback_exn(v_cb, v_frame);
    if (Is_exception_result(res)) {
      /* Propagate the exception back to the caller of iter_frames. */
      caml_raise(Extract_exception(res));
    }
    /* No allocation that survives the callback – the bigarray lives only
       until the callback returns, which is exactly what we need. */
  }

  CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   iter_frames_raw : t ->
                     (int64 -> int -> int -> bigarray -> unit) -> unit
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_iter_frames_raw(value v_handle,
                                                    value v_cb) {
  CAMLparam2(v_handle, v_cb);
  CAMLlocal3(v_ts, v_caplen, v_len);

  pcapng::File* file = *(pcapng::File**)Data_custom_val(v_handle);
  if (!file) caml_failwith("pcapng: file already closed");

  for (auto it = file->begin(); it != file->end(); ++it) {
    const pcapng::frame& fr = *it;

    v_ts     = caml_copy_int64((int64_t)fr.timestamp);
    v_caplen = Val_int(fr.caplen);
    v_len    = Val_int(fr.len);

    /* Build a temporary bigarray for the payload. */
    value v_data = caml_ba_alloc(CAML_BA_UINT8 | CAML_BA_EXTERNAL,
                                 1,
                                 (char*)fr.data,
                                 fr.caplen);

    /* Call the OCaml function with four arguments. */
    value args[4] = { v_ts, v_caplen, v_len, v_data };
    value res = caml_callbackN_exn(v_cb, 4, args);
    if (Is_exception_result(res))
      caml_raise(Extract_exception(res));
  }

  CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   Register the primitives for the .cma/.cmxa generated by ocamlc/ocamlopt.
   ---------------------------------------------------------------------- */
static struct caml_named_value caml_named_prims[] = {
  {"pcapng_open_file",   caml_pcapng_open_file},
  {"pcapng_close",       caml_pcapng_close},
  {"pcapng_iter_frames", caml_pcapng_iter_frames},
  {"pcapng_iter_frames_raw", caml_pcapng_iter_frames_raw},
  {NULL, NULL}
};

extern "C" CAMLprim value caml_pcapng_register_prims(value unit) {
  CAMLparam1(unit);
  for (int i = 0; caml_named_prims[i].name != NULL; ++i) {
    caml_register_named_value(caml_named_prims[i].name,
                              caml_named_prims[i].function);
  }
  CAMLreturn(Val_unit);
}
```

### How to compile

Assuming the source files are `pcapng.mli`, `pcapng.ml` (the implementation that
just forwards to the C primitives) and `pcapng_stubs.cpp`:

```sh
# Compile the C++ stub (adjust the include path to your OCaml installation)
ocamlopt -c -ccopt -std=c++17 -I $(ocamlc -where) pcapng_stubs.cpp

# Compile the OCaml files
ocamlopt -c pcapng.mli
ocamlopt -c pcapng.ml

# Build a library
ocamlopt -a -o libpcapng.cmxa \
    pcapng.o pcapng_stubs.o \
    -cclib -lstdc++   # link the C++ standard library

# Or a bytecode library
ocamlc -a -o libpcapng.cma \
    pcapng.cmo pcapng_stubs.o \
    -cclib -lstdc++
```

Now the library can be used from OCaml:

```ocaml
(* test.ml -------------------------------------------------------------- *)
let () =
  let file = Pcapng.open_file "capture.pcapng" in
  (* high‑level version *)
  Pcapng.iter_frames file (fun fr ->
      Printf.printf "ts=%Ld caplen=%d len=%d\n%!"
        fr.ts fr.caplen fr.len
    );
  (* low‑level version – a few percent faster on the 800 M‑frame benchmark *)
  Pcapng.iter_frames_raw file (fun ts caplen len data ->
      (* data is a bigarray; for example, just inspect the first byte *)
      if caplen > 0 then
        Printf.printf "first byte = %d\n%!" (Char.code (Bigarray.Array1.get data 0))
    );
  Pcapng.close file
```

Compile the test program with the same linking flags, and you have a fully
functional, high‑performance OCaml binding to the C++ `libpcapng` iterator.
